mapper.update:
UPDATE t_outbox_event
SET status = 'PROCESSING', processing_token = #{token}, processing_until = #{until}
WHERE id = #{id}
  AND (status = 'PENDING' OR (status = 'PROCESSING' AND processing_until < NOW()))

UPDATE t_outbox_event
SET status = 'PUBLISHED', published_at = NOW(), processing_token = NULL, processing_until = NULL
WHERE id = #{id}
  AND status = 'PROCESSING'
  AND processing_token = #{token}

UPDATE t_outbox_event
SET status = 'PENDING', retry_count = retry_count + 1, processing_token = NULL, processing_until = NULL
WHERE id = #{id}
  AND status = 'PROCESSING'
  AND processing_token = #{token}
